-- 2026-06-22: knee_meniscus_conservative — фазы «Путь» + структурированные критерии перехода (K1 мениск колена).
-- Источник: PROTOCOLS/knee/*.md + PROTOCOLS/knee/_extractions_meniscus.json (knee_meniscus_conservative).
-- Контент в ПАЦИЕНТСКОМ регистре (первичная версия) — источник истины после деплоя AdminContent.
-- Решения Vadim 2026-06-22: нумерация фаз с 1;
--   terminal-фаза несёт критерии возврата к спорту/выписки.
-- Классификация (knee-конвенция, как acl_refresh): measurement = ROM-градусы (knee_flexion/extension_degrees,
--   source='rom') + боль ВАШ (vas_score, source='pain'); всё прочее (сила/LSI/hop/выпот/KOOS/срок) =
--   instructor_check с порогом в тексте label. Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц.

BEGIN;

-- 1. Фазы knee_meniscus_conservative
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
(
    'knee_meniscus_conservative', 1,
    'Успокоить колено и вернуть движение',
    'Первые недели программы',
    '0-6',
    'Стартовый этап без операции. Здесь не нужно ничего «защищать» или «беречь от нагрузки» — задача снять боль и отёк, вернуть полное сгибание и разгибание и заново научить переднюю мышцу бедра включаться. Движение и постепенная нагрузка безопасны и помогают колену, а не вредят ему.',
    '["Снять боль и отёк, чтобы колено перестало «гудеть»","Вернуть полный и комфортный объём движения — сгибание и разгибание","«Разбудить» переднюю мышцу бедра и научиться её включать","Вернуть ровную походку без хромоты","Понять, почему движение и нагрузка при таком разрыве безопасны"]',
    '["Временно отложите то, что резко раздражает колено: глубокие приседания с весом, скручивания и развороты, бег и прыжки","Не нагружайтесь через сильную боль (выше 5 из 10)"]',
    '["Боль на нагрузке не выше 3 из 10","Колено не отекает после привычной дневной активности","Полное разгибание и сгибание колена восстановлены","Ровная походка без хромоты"]',
    'dumbbell', '#10B981', '#EDFAF5',
    'Снять отёк, вернуть движение, включить бедро',
    '["Ходьба в комфортном объёме и велотренажёр без или с лёгким сопротивлением","Лёгкие упражнения на объём движения и включение передней мышцы бедра и ягодиц","Изометрия и упражнения с опорой на ногу в безболезненном диапазоне"]',
    '["Боль во время и после занятия до 5 из 10 допустима — это нормально и безопасно","Если боль выше 5 из 10 или нарастает отёк — снизьте нагрузку на одно-два занятия"]',
    '["Несколько коротких занятий в течение дня лучше одного длинного","В покое держите ногу приподнятой, чтобы отёк лучше уходил","Прикладывайте холод после нагрузки, если колено реагирует отёком"]',
    '["Колено по-настоящему заклинило и не разгибается полностью","Резкий большой отёк колена","Боль в икре вместе с отёком голени — срочно к врачу (возможен тромб)","Температура, горячий красный болезненный сустав — срочно к врачу"]',
    '[{"q":"Если мениск «порвался», не доломаю ли я его движением и нагрузкой?","a":"Нет. При таком неоперационном разрыве колено не «висит на нитке». Постепенная грамотная нагрузка укрепляет колено и не ускоряет износ. Боль до умеренного уровня во время упражнений — это нормально и безопасно."},{"q":"Мне сказали «разрыв мениска» по МРТ. Значит, нужна операция?","a":"Чаще всего нет. У многих людей без боли на МРТ тоже находят разрывы — это нередко возрастные изменения. При таком разрыве операция не обязательна и не даёт преимущества перед упражнениями."}]'
),
(
    'knee_meniscus_conservative', 2,
    'Сила и уверенный контроль',
    'Набор силы и устойчивости',
    '6-12',
    'Колено успокоилось — теперь делаем ногу заметно сильнее и учим её уверенно держать нагрузку. Прогрессивная силовая работа на бедро и ягодицы плюс упражнения на баланс и контроль движения. Нагрузку повышаем постепенно, следя, чтобы колено не отекало к следующему дню.',
    '["Сделать ногу заметно сильнее: бедро спереди и сзади, ягодицы","Научить колено уверенно держать нагрузку и не «подводить»","Постепенно поднимать переносимость нагрузки и объём активности"]',
    '["Бег, прыжки и развороты пока вводит куратор — дозированно и только при хорошей переносимости","Не форсируйте вес в ущерб технике: колено должно идти над стопой, без заваливания внутрь"]',
    '["Боль на нагрузке не выше 2 из 10","Сила бедра и ягодиц подтянулась к здоровой ноге","Уверенный присед на одной ноге без заваливания колена","Колено уверенно держит нагрузку, нет отёка после тренировки"]',
    'dumbbell', '#F59E0B', '#FFF8ED',
    'Прогрессивная сила, баланс, устойчивость колена',
    '["Прогрессивная силовая на бедро и ягодицы, в том числе упражнения на одной ноге на обе стороны","Упражнения на баланс и контроль оси, смена опорной поверхности","Кардио с возрастающим сопротивлением; со временем — лёгкие подскоки после набора силовой базы"]',
    '["Рабочий диапазон боли — до 5 из 10, без нарастания отёка к следующему дню","Повышайте нагрузку по простому правилу: если в последнем подходе остаётся запас в 2 и более повторения — можно добавить"]',
    '["Регулярность важнее интенсивности — занимайтесь по плану несколько раз в неделю","Следите за коленом на следующий день: лёгкая усталость мышц — норма, нарастающий отёк — сигнал сбавить"]',
    '["Колено по-настоящему заклинило и не разгибается","Повторяющиеся «подкашивания» с отёком","Отёк колена упорно возвращается, несмотря на снижение нагрузки"]',
    '[{"q":"Почему мы качаем мышцы, а не «чиним» сам разрыв?","a":"Цель не «закрыть» разрыв, а вернуть колену силу, контроль и устойчивость. Когда мышцы бедра и ягодиц сильные, колено меньше раздражается, и вы возвращаетесь к жизни без операции."},{"q":"Колено иногда «щёлкает». Это значит, что становится хуже?","a":"Само по себе щёлканье или «зацеп» — не признак ухудшения и не повод для операции. Тревожно только если колено реально заклинивает и перестаёт разгибаться — тогда скажите куратору."}]'
),
(
    'knee_meniscus_conservative', 3,
    'Возврат к активности и жизнь без рецидивов',
    'Спорт и долгосрочное самоведение',
    '12+',
    'Финальный этап: возвращаемся к желаемой активности — вплоть до бега, прыжков и игр со сменой направления, если это ваша цель. Силу и контроль доводим до уровня здоровой ноги. И осваиваем «программу на всю жизнь»: как поддерживать колено самостоятельно — особенно важно, если есть возрастной фон сустава, тогда это управление, а не разовый курс.',
    '["Вернуться к желаемой активности — вплоть до бега, прыжков и смены направления","Довести силу и контроль до уровня здоровой ноги","Освоить поддерживающую программу на каждый день, чтобы удерживать результат"]',
    '["Возврат к бегу, прыжкам и разворотам — только после прохождения тестов готовности","Если есть возрастной фон сустава или лишний вес — высокоударные нагрузки наращивайте мягче, под свою переносимость"]',
    '["Боль при целевой нагрузке не выше 2 из 10","Сила и прыжковые тесты не меньше 90% от здоровой ноги","Психологическая готовность вернуться к своей активности","Нет отёка после спорт-специфической нагрузки"]',
    'trophy', '#EC4899', '#FFF9E6',
    'Возврат к спорту по тестам и программа на всю жизнь',
    '["Полный спектр силовой и мощностной работы, подскоки, спорт-специфические упражнения","Самостоятельная поддерживающая программа дома и в зале"]',
    '["Эпизодический дискомфорт допустим; ориентир — нет стойкого нарастания боли или отёка после нагрузки","Правило 24 часов: симптомы не должны ухудшаться к следующему дню"]',
    '["Сделайте поддерживающие упражнения привычкой — это удерживает колено сильным надолго","После новых или ударных нагрузок следите за реакцией колена на следующий день"]',
    '["Новая настоящая блокада колена (не разгибается)","Нарастающие боль или отёк, которые не уходят при снижении нагрузки — покажитесь врачу"]',
    '[{"q":"Смогу ли я вернуться к бегу и спорту со сменой направления?","a":"Да, если это ваша цель и вы прошли тесты на силу и прыжки — обычно не меньше 90% от здоровой ноги. Возврат идёт по готовности тела, а не по календарю."},{"q":"Это «вылечилось» навсегда или вернётся?","a":"Если есть возрастной фон сустава — думайте об этом как об управлении, а не разовом курсе. Поддерживающие упражнения «на всю жизнь» удерживают результат — это нормальная и эффективная стратегия."}]'
