ON CONFLICT (program_type, phase_number) DO NOTHING;

-- 2. Критерии перехода knee_meniscus_conservative (JOIN на rehab_phases по program_type+phase_number → phase_id)
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  (1, 'pain_low_p1', 'Боль на нагрузке не выше 3 из 10', 'measurement', 'vas_score'::varchar, 'pain'::varchar, '<='::varchar, 3::numeric, NULL::numeric, 7::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'full_ext_p1', 'Полное разгибание колена (0°)', 'measurement', 'knee_extension_degrees'::varchar, 'rom'::varchar, '<='::varchar, 0::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 20::smallint, TRUE),
  (1, 'flex_120_p1', 'Сгибание колена не менее 120° (или симметрично здоровой ноге)', 'measurement', 'knee_flexion_degrees'::varchar, 'rom'::varchar, '>='::varchar, 120::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 30::smallint, TRUE),
  (1, 'no_swelling_daily_p1', 'Колено не отекает после привычной дневной активности', 'self_report', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 7::smallint, 'Колено остаётся спокойным после обычного дня — ходьбы, дел по дому, лестницы?'::text, 'Сравните колено вечером с утром: если к вечеру оно заметно припухает и теплеет — отметьте «нет».'::text, 40::smallint, TRUE),
  (1, 'effusion_trace_p1', 'Выпот не более следового (тест смахивания не выше 1+) — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 50::smallint, TRUE),
  (1, 'gait_normal_p1', 'Походка нормализована, без хромоты — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 60::smallint, TRUE),
  (1, 'quad_activation_p1', 'Передняя мышца бедра включается без отставания при выпрямлении — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 70::smallint, TRUE),
  (2, 'pain_low_p2', 'Боль на нагрузке не выше 2 из 10 при силовой и базовой работе на контроль', 'measurement', 'vas_score'::varchar, 'pain'::varchar, '<='::varchar, 2::numeric, NULL::numeric, 7::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (2, 'quad_lsi_80_p2', 'Сила передней мышцы бедра не менее 80% от здоровой ноги — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 20::smallint, TRUE),
  (2, 'hamstring_lsi_80_p2', 'Сила задней поверхности бедра не менее 80% от здоровой ноги — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 30::smallint, TRUE),
  (2, 'glute_lsi_80_p2', 'Сила ягодичных не менее 80% от здоровой ноги — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 40::smallint, FALSE),
  (2, 'sls_control_p2', 'Контролируемый присед на одной ноге без заваливания колена внутрь, не менее 10 повторений — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 50::smallint, TRUE),
  (2, 'knee_confident_p2', 'Колено уверенно держит нагрузку, нет ощущения нестабильности', 'self_report', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 7::smallint, 'Колено уверенно держит вас на нагрузке — приседе, лестнице, ходьбе — без чувства, что оно вот-вот «подведёт»?'::text, 'Отметьте «нет», если бывают эпизоды неуверенности или «подкашивания» под нагрузкой.'::text, 60::smallint, TRUE),
  (2, 'no_effusion_load_p2', 'Нет выпота после тренировочной нагрузки (тест смахивания 0 или следовой) — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 70::smallint, TRUE),
  (3, 'pain_low_p3', 'Боль при целевой нагрузке не выше 2 из 10', 'measurement', 'vas_score'::varchar, 'pain'::varchar, '<='::varchar, 2::numeric, NULL::numeric, 7::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (3, 'quad_lsi_90_p3', 'Сила передней мышцы бедра не менее 90% от здоровой ноги — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 20::smallint, TRUE),
  (3, 'hamstring_glute_lsi_90_p3', 'Сила задней поверхности бедра и ягодичных не менее 90% от здоровой ноги — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 30::smallint, TRUE),
  (3, 'hop_lsi_90_p3', 'Прыжковые тесты (батарея) не менее 90% симметрии со здоровой ногой — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 40::smallint, FALSE),
  (3, 'koos_sport_qol_p3', 'Опросники KOOS Sport и качества жизни на приемлемом для вас уровне (единого порога нет, цель определяет куратор) — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 50::smallint, FALSE),
  (3, 'ikdc_norm_p3', 'Опросник IKDC в пределах нормы для вашего пола и возраста — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 60::smallint, FALSE),
  (3, 'psych_ready_p3', 'Я психологически готов вернуться к своей активности или спорту', 'self_report', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 7::smallint, 'Вы чувствуете уверенность и готовность вернуться к своей активности или спорту без страха за колено?'::text, 'Отметьте «нет», если остаётся тревога или вы избегаете движений из-за колена.'::text, 70::smallint, TRUE),
  (3, 'no_effusion_sport_p3', 'Нет выпота после спорт-специфической нагрузки — проверяет куратор очно', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 80::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'knee_meniscus_conservative' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
